import React, { useState } from 'react';
import { Container, Box, Typography, Button, TextField, CircularProgress, Alert } from '@mui/material';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import API from '../../services/api';

// Leaflet marker icon fix
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
  iconUrl: require('leaflet/dist/images/marker-icon.png'),
  shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});


function LocationMarker({ position, setPosition }) {
  const map = useMapEvents({
    click(e) {
      setPosition(e.latlng);
      map.flyTo(e.latlng, map.getZoom());
    },
    locationfound(e) {
      setPosition(e.latlng);
      map.flyTo(e.latlng, map.getZoom());
    },
  });

  return position === null ? null : (
    <Marker position={position}></Marker>
  );
}

export default function BreakdownAssistance() {
  const [position, setPosition] = useState(null);
  const [notes, setNotes] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [carId, setCarId] = useState(''); // TODO: Get this from a dropdown of the user's cars

  const handleGetLocation = () => {
    // Note: useMapEvents.locationfound is better
  };

  const handleSubmit = async () => {
    if (!position) {
      setError('Please select a location on the map.');
      return;
    }
    if (!carId) {
      setError('Please select a car.');
      return;
    }

    setLoading(true);
    setError('');
    setSuccess('');

    try {
      const breakdownData = {
        car: carId,
        latitude: position.lat,
        longitude: position.lng,
        notes,
      };
      await API.post('/breakdowns', breakdownData);
      setSuccess('Breakdown request submitted successfully. We will be in touch shortly.');
    } catch (e) {
      console.error(e);
      setError('Failed to submit breakdown request.');
    } finally {
      setLoading(false);
    }
  };


  return (
    <Container sx={{ mt: 4 }}>
      <Typography variant="h4" gutterBottom>
        Breakdown Assistance
      </Typography>
      <Typography variant="body1" gutterBottom>
        Click on the map to select your location, or we can try to find you.
      </Typography>

      <Box sx={{ height: '400px', mb: 3 }}>
        <MapContainer center={{ lat: 51.505, lng: -0.09 }} zoom={13} style={{ height: '100%', width: '100%' }}>
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          />
          <LocationMarker position={position} setPosition={setPosition} />
        </MapContainer>
      </Box>

      {/* TODO: Add a dropdown to select one of the user's cars */}
      <TextField
        label="Car ID (for now)"
        value={carId}
        onChange={(e) => setCarId(e.target.value)}
        fullWidth
        sx={{ mb: 2 }}
      />

      <TextField
        label="Additional Notes (e.g., 'flat tire', 'engine won't start')"
        multiline
        rows={4}
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
        fullWidth
        sx={{ mb: 2 }}
      />

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <Button
        variant="contained"
        color="primary"
        onClick={handleSubmit}
        disabled={loading}
        fullWidth
      >
        {loading ? <CircularProgress size={24} /> : 'Submit Breakdown Request'}
      </Button>
    </Container>
  );
}
